    assign ost_ctrl_write   = bit_set(ost_ctrl_id, ost_ctrl_valid);
    assign ost_burst_read   = bit_set(beat_id, next_burst);

    assign next_ctrl        = in_BURST_RREADY & ost_ctrl_empty_n;
